xpath.script:
//
document.addEventListener('click', async function (event) {
    if (event.target.classList.contains('o_estate_api_button')) {
        const btn = event.target;

        // عرض SweetAlert2 Form بدلاً من الـ Prompt القديم
        const { value: formValues } = await Swal.fire({
            title: 'طلب معاينة عقار',
            html:
                '<input id="swal-name" class="swal2-input" placeholder="الاسم بالكامل">' +
                '<input id="swal-phone" class="swal2-input" placeholder="رقم التليفون">' +
                '<input id="swal-address" class="swal2-input" placeholder="عنوانك الحالي">',
            focusConfirm: false,
            confirmButtonText: 'إرسال الطلب',
            showCancelButton: true,
            cancelButtonText: 'إلغاء',
            preConfirm: () => {
                const name = document.getElementById('swal-name').value;
                const phone = document.getElementById('swal-phone').value;
                const address = document.getElementById('swal-address').value;
                if (!name || !phone) {
                    Swal.showValidationMessage('من فضلك أدخل الاسم ورقم التليفون');
                }
                return { name, phone, address };
            }
        });

        if (formValues) {
            const data = {
                property_name: btn.getAttribute('data-product-name'),
                price: btn.getAttribute('data-product-price'),
                url: window.location.origin + btn.getAttribute('data-product-url'),
                address: formValues.address,
                client_phone: formValues.phone,
                client_name: formValues.name
            };

            try {
                // إظهار Loading أثناء الإرسال
                Swal.fire({ title: 'جاري الإرسال...', didOpen: () => { Swal.showLoading() } });

                const response = await fetch('/api/estate/inquiry', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ params: data })
                });

                const result = await response.json();
                if (result.result && result.result.status === 'success') {
                    Swal.fire('تم بنجاح!', 'تم استلام طلبك، سيتواصل معك فريقنا قريباً.', 'success');
                }
            } catch (error) {
                Swal.fire('خطأ!', 'فشل إرسال الطلب، حاول مرة أخرى.', 'error');
            }
        }
    }
});
//
